import { ConfigProvider as AntdConfigProvider } from 'antd';
import theme from '@spotter/design-token/lib/antdTheme.json';
import React, { ReactNode, useContext } from 'react';
import { RouteObject } from 'react-router-dom';

export type ConfigContextPropsType = {
    locale?: string;
    routes?: RouteObject[];
};

export const SptComponentContext = React.createContext<ConfigContextPropsType>({
    locale: 'default',
    routes: [],
});

export const { Consumer: ConfigConsumer } = SptComponentContext;

export const SptComponentProvider: React.FC<{
    prefixCls?: string;
    routes?: RouteObject[];
    children?: ReactNode | undefined;
}> = ({ children, routes = [] }) => {
    const { ...restConfig } = useContext(AntdConfigProvider.ConfigContext);
    const sptProvide = useContext(SptComponentContext);

    return (
        <AntdConfigProvider theme={theme} {...restConfig}>
            <SptComponentContext.Provider value={{ ...sptProvide, routes }}>
                {children}
            </SptComponentContext.Provider>
        </AntdConfigProvider>
    );
};
